function readBootstrappedPayload(markup) {
  const startTag = '<script id="workspace-audit-bootstrap" type="application/json">';
  const startIndex = markup.indexOf(startTag);
  if (startIndex === -1) return null;

  const contentStart = startIndex + startTag.length;
  const endIndex = markup.indexOf("</script>", contentStart);
  if (endIndex === -1) return null;

  return markup.slice(contentStart, endIndex);
}

function hasInlineHeadStyle(markup) {
  const headMatch = markup.match(/<head\b[^>]*>([\s\S]*?)<\/head>/i);
  if (!headMatch) return false;
  return /<style(?:\s|>)/i.test(headMatch[1]);
}

